VALUES
  ('social-worker-moex-06210', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關單案研究設計（single-subject design）的特性，下列敘述何者錯誤？', '["運用了時間序列設計的邏輯", "主要優點是其外部效度頗高", "有特殊的測量問題，因此推薦使用三角測量法", "會產生有關反應性與社會期待偏頗的測量問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06211', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一項親職團體方案，目標在提升高風險家庭父母的親職能力。為了評估方案成效，設計了對照組，即進 行親職團體時，另有一聯誼性質團體，參與者可以自由選擇參與那一個團體。3個月後評估，親職能力的 各項指標，包括陪伴孩子的時間、給予孩子正向回應、親子溝通品質等，結果親職團體組的平均分數都 高於對照組，下列何種因素最可能威脅此一方案評估研究的內在效度？', '["耗損（mortality）", "選樣（selection）", "成熟效應（maturation）", "工具反應效應（reactive effect）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06212', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關離散量數的敘述，下列何者正確？', '["變異數偵查數值變動的能力優於平均差", "各數值與平均數的差異愈大，則標準差愈小", "全距是一種精確的分配變異指標", "通常全距約為4倍的標準差"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06213', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某老師為班上成績退步的一些同學進行輔導，果然下一次考試這些同學都有大幅的進步。除了課輔或有 或無的效果外，最有可能是下列何種效應的結果？', '["成熟效應（maturation effect）", "統計的迴歸效應（statistical regression effect）", "歷史效應（history effect）", "測驗效應（testing effect）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06214', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列不同的調查訪問方法，執行需要的經費成本由高至低依序為下列何者？', '["電話訪問＞郵寄問卷＞面訪＞網路填答", "面訪＞網路填答＞電話訪問＞郵寄問卷", "郵寄問卷＞電話訪問＞網路填答＞面訪", "面訪＞電話訪問＞郵寄問卷＞網路填答"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06215', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究所學生以新住民充權方案的設計與評估為碩士論文主題。為此，研究者參加每次的方案活動， 告知團體成員研究計畫，也訪談團體的領導者與部分參與者。試問，研究者所採取的研究角色是下列何 者？', '["完全參與者", "觀察式參與者", "參與式觀察者", "完全觀察者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06216', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '使用1990、2000與2010年內政部的「婦女婚育與就業調查」資料，分析20～40歲女性就業、生育及 結婚意願的變遷。這是下列那一種研究？', '["橫斷性研究（cross-sectional study）", "同組研究（panel study）", "世代研究（cohort study）", "趨勢研究（trend study）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06217', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於文獻回顧的敘述，下列何者錯誤？', '["閱讀文獻是研究初期相當重要的工作，應儘早結束，以便專注進行研究", "撰寫文獻回顧，要呈現出自己的意見及想法，避免僅是堆砌文獻", "藉由文獻探討的過程，研究者可以更清楚要提問什麼樣的研究問題", "系統性文獻回顧（systematic reviews）可以運用進階的統計方法，整理文獻中的研究結果，本身就是一 個研究方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06218', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社會工作者常應用官方或半官方的資料來進行分析。下列運用現存資料研究的敘述，何者正確？①研究', '["研究者不必自己蒐集資料，可以節省時間", "資料已經有人使 用過，品質不成問題", "現存資料的定義如果不符合研究的變數定義，會有測量的效度問題", "僅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06219', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關方案評估中使用量化分析不易達到統計上顯著的原因，下列敘述何者錯誤？', '["方案目標有時不易以量化工具測量或統計分析", "方案評估結果會因與既得利益相牴觸，難以產生實際改變", "用以評估的個案量常有不足，不符合量化要求之數量", "方案執行時間較短，較難產生實際顯著差異效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
